mapper.select:
SELECT id, product_name AS productName, category, price, stock_qty AS stockQty, image_url AS imageUrl, created_at AS createdAt FROM product WHERE 1=1
AND DATE(created_at) >= #{startDate}
AND DATE(created_at) <= #{endDate}
ORDER BY
id product_name category price stock_qty created_at id
ASC DESC

mapper.update:
UPDATE product
SET stock_qty = stock_qty - #{qty}
WHERE id = #{productId}
AND stock_qty >= #{qty}

UPDATE product
SET stock_qty = stock_qty + #{qty}
WHERE id = #{productId}
